    private void cardpaytxt3KeyPressed(java.awt.event.KeyEvent evt) {//GEN-FIRST:event_cardpaytxt3KeyPressed
        String cardnum = cardpaytxt3.getText();
        int cardnum_length = cardnum.length();
        char card = evt.getKeyChar();

        if (Character.isDigit(card)) {
            if (cardnum_length < 16) {
                cardpaytxt3.setEditable(true);
            } else {
                cardpaytxt3.setEditable(false);
            }
        } else {
            if (Character.isISOControl(card)) {
                cardpaytxt3.setEditable(true);
            } else {
                cardpaytxt3.setEditable(false);
            }
        }
    }//GEN-LAST:event_cardpaytxt3KeyPressed

    private void cardpaytxt5KeyPressed(java.awt.event.KeyEvent evt) {//GEN-FIRST:event_cardpaytxt5KeyPressed
        String cardcode = cardpaytxt5.getText();
        int cardcode_length = cardcode.length();
        char code = evt.getKeyChar();

        if (Character.isDigit(code)) {
            if (cardcode_length < 3) {
                cardpaytxt5.setEditable(true);
            } else {
                cardpaytxt5.setEditable(false);
            }
        } else {
            if (Character.isISOControl(code)) {
                cardpaytxt5.setEditable(true);
            } else {
                cardpaytxt5.setEditable(false);
            }
        }
    }//GEN-LAST:event_cardpaytxt5KeyPressed

