    private void cardpaybtn1ActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_cardpaybtn1ActionPerformed
        if (cardpaytxt2.getText().equals("") || cardpaytxt3.getText().equals("") || cardpaytxt5.getText().equals("")
                || jComboBox2.getSelectedItem().equals("Month") || jComboBox1.getSelectedItem().equals("Year") 
                || jComboBox2.getSelectedIndex()==1 || jComboBox1.getSelectedIndex()==1)
                JOptionPane.showMessageDialog(null, "ENTER ALL FIELDS!");
        else{
            JOptionPane.showMessageDialog(null, "Payment Successful!");
            cardpaytxt2.setText("");
            cardpaytxt3.setText("");
            cardpaytxt5.setText("");
            jComboBox2.setSelectedIndex(0);
            jComboBox1.setSelectedIndex(0);
        }       
    }//GEN-LAST:event_cardpaybtn1ActionPerformed

    private void cardpaytxt2KeyPressed(java.awt.event.KeyEvent evt) {//GEN-FIRST:event_cardpaytxt2KeyPressed
        String cardname = cardpaytxt2.getText();
        int cardname_length = cardname.length();
        char cardname2 = evt.getKeyChar();

        if (Character.isLetter(cardname2)) {

            if (cardname_length < 30) {
                cardpaytxt2.setEditable(true);
            } else {
                cardpaytxt2.setEditable(false);
            }
        } else {
            if (Character.isWhitespace(cardname2) || Character.isISOControl(cardname2)) {
                cardpaytxt2.setEditable(true);
            } else {
                cardpaytxt2.setEditable(false);
            }
        }
    }//GEN-LAST:event_cardpaytxt2KeyPressed

